import{_ as t,a,b as d,c as n}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as o,o as s,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Yandex Channel شامل کریں","description":"","frontmatter":{},"headers":[],"relativePath":"ur/upload/yandex.md","filePath":"ur/upload/yandex.md","lastUpdated":1781962217000}'),r={name:"ur/upload/yandex.md"};function p(c,e,h,u,m,x){return s(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="yandex-channel-شامل-کریں" tabindex="-1">Yandex Channel شامل کریں <a class="header-anchor" href="#yandex-channel-شامل-کریں" aria-label="Permalink to &quot;Yandex Channel شامل کریں&quot;">​</a></h1><h2 id="پہلے-کیا-چاہیے" tabindex="-1">پہلے کیا چاہیے <a class="header-anchor" href="#پہلے-کیا-چاہیے" aria-label="Permalink to &quot;پہلے کیا چاہیے&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ضرورت</th><th>وجہ</th></tr></thead><tbody><tr><td>Yandex account</td><td>sign in اور Yandex Disk authorize کرنے کے لیے</td></tr><tr><td>Yandex OAuth app</td><td><code>Client ID</code> اور <code>Client Secret</code> generate کرنے کے لیے</td></tr><tr><td>آپ کا ImgBed domain</td><td>OAuth redirect URI کے لیے</td></tr><tr><td>دستیاب Yandex Disk storage</td><td>اصل file storage location کے طور پر</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-yandex-oauth-app-بنائیں" tabindex="-1">Step 1: Yandex OAuth App بنائیں <a class="header-anchor" href="#step-1-yandex-oauth-app-بنائیں" aria-label="Permalink to &quot;Step 1: Yandex OAuth App بنائیں&quot;">​</a></h3><ol><li>Yandex OAuth app creation page کھولیں:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>اگر sign in page پر redirect ہو جائیں، پہلے اپنے Yandex account سے sign in کریں۔</li><li>نیا app بنائیں۔</li><li>app کو قابل شناخت نام دیں، مثلاً <code>imgbed-yandex</code>۔</li><li>callback یا redirect URL settings تلاش کریں۔</li><li>درج کریں:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="step-2-permissions-confirm-کریں" tabindex="-1">Step 2: Permissions Confirm کریں <a class="header-anchor" href="#step-2-permissions-confirm-کریں" aria-label="Permalink to &quot;Step 2: Permissions Confirm کریں&quot;">​</a></h3><p>موجودہ ImgBed Yandex integration کے لیے <code>Yandex.Disk REST API</code> کے تحت یہ چار permissions رکھیں:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Purpose</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>ImgBed کو app folder میں files store کرنے دیتا ہے</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>files اور download links پڑھتا ہے</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>files upload کرتا ہے، folders بناتا ہے، اور files delete کرتا ہے</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>disk quota اور used space پڑھتا ہے</td></tr></tbody></table><p>اگر <code>Yandex ID API</code> کے تحت یہ permissions بھی نظر آئیں تو optional ہیں:</p><table tabindex="0"><thead><tr><th>Permission Text</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>Optional</td></tr><tr><td><code>Access to email address</code></td><td>Optional</td></tr></tbody></table><p>Core upload، download، deletion، اور quota features کا انحصار اوپر والی چار <code>Yandex.Disk REST API</code> permissions پر ہے۔</p><p><img src="'+t+'" alt="Configure Yandex Disk permissions" loading="lazy"></p><h3 id="step-3-app-credentials-copy-کریں" tabindex="-1">Step 3: App Credentials Copy کریں <a class="header-anchor" href="#step-3-app-credentials-copy-کریں" aria-label="Permalink to &quot;Step 3: App Credentials Copy کریں&quot;">​</a></h3><p>app بننے کے بعد copy کریں:</p><table tabindex="0"><thead><tr><th>Yandex Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+a+'" alt="Record Client ID and Secret" loading="lazy"></p><h3 id="step-4-imgbed-میں-yandex-channel-بھریں" tabindex="-1">Step 4: ImgBed میں Yandex Channel بھریں <a class="header-anchor" href="#step-4-imgbed-میں-yandex-channel-بھریں" aria-label="Permalink to &quot;Step 4: ImgBed میں Yandex Channel بھریں&quot;">​</a></h3><p>Upload Settings میں <code>Yandex</code> منتخب کریں اور یہ fields بھریں:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>قابل شناخت نام، مثلاً <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td>Yandex app کا <code>Client ID</code></td></tr><tr><td>Client Secret</td><td>Yandex app کا <code>Client Secret</code></td></tr><tr><td>Refresh Token</td><td>ابھی خالی چھوڑ دیں</td></tr><tr><td>Root directory</td><td>Optional۔ default <code>imgbed</code> ہے۔</td></tr></tbody></table><p><img src="'+d+'" alt="Edit channel config" loading="lazy"></p><h3 id="step-5-refresh-token-حاصل-کریں" tabindex="-1">Step 5: Refresh Token حاصل کریں <a class="header-anchor" href="#step-5-refresh-token-حاصل-کریں" aria-label="Permalink to &quot;Step 5: Refresh Token حاصل کریں&quot;">​</a></h3><ol><li>ImgBed میں <code>Get Token</code> پر کلک کریں۔</li><li>جس Yandex account کو connect کرنا ہے اس میں sign in کریں۔</li><li>authorization prompt approve کریں۔</li><li>callback page ایک <code>Refresh Token</code> دکھائے گا۔</li><li>اسے copy کریں۔</li><li>ImgBed پر واپس آ کر <code>Refresh Token</code> field میں paste کریں۔</li></ol><p><img src="'+n+`" alt="Copy refresh token after authorization" loading="lazy"></p><h3 id="step-6-channel-save-کریں" tabindex="-1">Step 6: Channel Save کریں <a class="header-anchor" href="#step-6-channel-save-کریں" aria-label="Permalink to &quot;Step 6: Channel Save کریں&quot;">​</a></h3><p>تمام fields بھرنے کے بعد channel save کریں۔</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Yandex OAuth Console کھولیں</span></span>
<span class="line"><span>-&gt; app بنائیں</span></span>
<span class="line"><span>-&gt; https://your-domain.com/api/oauth/yandex/callback add کریں</span></span>
<span class="line"><span>-&gt; Yandex Disk permissions confirm کریں</span></span>
<span class="line"><span>-&gt; Client ID اور Client Secret copy کریں</span></span>
<span class="line"><span>-&gt; ImgBed میں Client ID / Client Secret بھریں</span></span>
<span class="line"><span>-&gt; Get Token پر کلک کریں</span></span>
<span class="line"><span>-&gt; callback page سے Refresh Token copy کریں</span></span>
<span class="line"><span>-&gt; ImgBed میں paste کر کے save کریں</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Register a Yandex app: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Get an authorization code through URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth token endpoint: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const k=o(r,[["render",p]]);export{f as __pageData,k as default};
